  // ---------- SIDEBAR ----------
  const sidebar = document.getElementById('sidebar');
  const sidebarOverlay = document.getElementById('sidebarOverlay');
  document.getElementById('hamburgerBtn').onclick = () => { sidebar.classList.add('open'); sidebarOverlay.classList.add('open'); };
  document.getElementById('sidebarClose').onclick = () => { sidebar.classList.remove('open'); sidebarOverlay.classList.remove('open'); };
  sidebarOverlay.onclick = () => { sidebar.classList.remove('open'); sidebarOverlay.classList.remove('open'); };
  document.querySelectorAll('.sidebar nav a').forEach(a => a.addEventListener('click', () => {
    sidebar.classList.remove('open'); sidebarOverlay.classList.remove('open');
  }));

  // ---------- HERO SLIDER ----------
  const slides = document.querySelectorAll('.hero-slide');
  const dotsWrap = document.getElementById('heroDots');
  let heroIndex = 0;
  slides.forEach((s, i) => {
    const dot = document.createElement('span');
    if (i === 0) dot.classList.add('active');
    dot.onclick = () => { heroIndex = i; renderHero(); };
    dotsWrap.appendChild(dot);
  });
  function renderHero(){
    slides.forEach((s,i)=> s.classList.toggle('active', i===heroIndex));
    dotsWrap.querySelectorAll('span').forEach((d,i)=> d.classList.toggle('active', i===heroIndex));
  }
  function heroMove(dir){
    heroIndex = (heroIndex + dir + slides.length) % slides.length;
    renderHero();
  }
  slides.forEach(s => s.addEventListener('click', (e) => {
    if(e.target.closest('button')) return;
    scrollToCategory(s.dataset.target);
  }));
  setInterval(()=>heroMove(1), 6000);

  function scrollToCategory(id){
    const el = document.getElementById(id);
    if(el) el.scrollIntoView({behavior:'smooth', block:'start'});
  }

  // ---------- IMAGE REPLACE ----------
  function replaceImage(input, imgId){
    const file = input.files[0];
    if(!file) return;
    const reader = new FileReader();
    reader.onload = e => { document.getElementById(imgId).src = e.target.result; };
    reader.readAsDataURL(file);
  }

  // ---------- SEARCH ----------
  function doSearch(){
    const q = document.getElementById('searchInput').value.trim().toLowerCase();
    if(!q) return;
    const cards = document.querySelectorAll('.product-card');
    let found = null;
    cards.forEach(c => {
      if(!found && c.dataset.search.includes(q)) found = c;
    });
    if(found){
      found.scrollIntoView({behavior:'smooth', block:'center'});
      found.classList.add('highlight');
      setTimeout(()=> found.classList.remove('highlight'), 2800);
    } else {
      alert('Produk tidak ditemukan. Coba kata kunci lain seperti "premium", "basic", "ceruty", atau nama warna ✨');
    }
  }
  document.getElementById('searchInput').addEventListener('keydown', e => { if(e.key === 'Enter') doSearch(); });

  // ---------- COLOR SWATCHES ----------
  const selectedColors = { premium: 'Coklat Mahogani', basic: 'Coklat Mahogani', ceruty: 'Mahogani' };
  function selectSwatch(el){
    const product = el.dataset.product;
    const color = el.dataset.color;
    selectedColors[product] = color;
    document.querySelectorAll('#swatch-' + product + ' .swatch-btn').forEach(b => b.classList.remove('active'));
    el.classList.add('active');
  }

  // ---------- CART ----------
  let cart = []; // {id, name, color, price, qty, img}

  function addToCart(name, price, productKey, imgId){
    const color = selectedColors[productKey];
    const img = document.getElementById(imgId).src;
    const key = name + '|' + color;
    const existing = cart.find(it => it.key === key);
    if(existing){ existing.qty += 1; }
    else{ cart.push({key, name, color, price, qty:1, img}); }
    renderCart();
    openCart();
  }

  function changeQty(key, delta){
    const it = cart.find(i => i.key === key);
    if(!it) return;
    it.qty += delta;
    if(it.qty <= 0) cart = cart.filter(i => i.key !== key);
    renderCart();
  }

  function removeItem(key){
    cart = cart.filter(i => i.key !== key);
    renderCart();
  }

  function resetCart(){
    if(cart.length === 0) return;
    if(confirm('Reset semua item di keranjang?')){
      cart = [];
      renderCart();
    }
  }

  function cartTotalValue(){
    return cart.reduce((sum, it) => sum + it.price * it.qty, 0);
  }

  function formatRp(n){
    return 'Rp ' + n.toLocaleString('id-ID');
  }

  function renderCart(){
    const wrap = document.getElementById('cartItemsWrap');
    const badge = document.getElementById('cartBadge');
    const totalCount = cart.reduce((s,i)=>s+i.qty,0);
    badge.textContent = totalCount;
    if(cart.length === 0){
      wrap.innerHTML = '<div class="cart-empty">Keranjang masih kosong 🩷</div>';
    } else {
      wrap.innerHTML = cart.map(it => `
        <div class="cart-item">
          <img src="${it.img}" alt="${it.name}">
          <div class="cart-item-info">
            <div class="nm">${it.name}</div>
            <div class="cl">${it.color} · ${formatRp(it.price)}</div>
            <div class="qty-ctrl">
              <button onclick="changeQty('${it.key}',-1)"><i class="fa-solid fa-minus"></i></button>
              <span>${it.qty}</span>
              <button onclick="changeQty('${it.key}',1)"><i class="fa-solid fa-plus"></i></button>
            </div>
          </div>
          <button class="remove-item" onclick="removeItem('${it.key}')"><i class="fa-solid fa-trash"></i></button>
        </div>
      `).join('');
    }
    document.getElementById('cartTotal').textContent = formatRp(cartTotalValue());
    renderOrderItems();
  }

  // ---------- CART PANEL TOGGLE ----------
  const cartPanel = document.getElementById('cartPanel');
  document.getElementById('cartBtn').onclick = openCart;
  document.getElementById('closeCart').onclick = () => cartPanel.classList.remove('open');
  function openCart(){ cartPanel.classList.add('open'); }
  function goToOrder(){
    cartPanel.classList.remove('open');
    document.getElementById('pesan').scrollIntoView({behavior:'smooth'});
  }

  // ---------- ORDER FORM ITEMS ----------
  function renderOrderItems(){
    const listWrap = document.getElementById('orderItemsList');
    if(cart.length === 0){
      listWrap.innerHTML = '<div class="cart-empty" id="orderEmptyMsg">Keranjang masih kosong. Tambahkan produk dari katalog terlebih dahulu ✨</div>';
    } else {
      listWrap.innerHTML = cart.map(it => `
        <label class="order-item-check">
          <input type="checkbox" class="ord-check" data-key="${it.key}" data-price="${it.price * it.qty}" checked onchange="updateOrderTotal()">
          <span class="oi-name">${it.name} — ${it.color} (x${it.qty})</span>
          <span class="oi-price">${formatRp(it.price * it.qty)}</span>
        </label>
      `).join('');
    }
    updateOrderTotal();
  }

  function updateOrderTotal(){
    const checks = document.querySelectorAll('.ord-check');
    let total = 0;
    checks.forEach(c => { if(c.checked) total += parseInt(c.dataset.price); });
    document.getElementById('orderTotalAmt').textContent = formatRp(total);
    return total;
  }

  // ---------- PAYMENT SELECTION ----------
  let selectedPayment = null;
  function selectPayment(method){
    selectedPayment = method;
    document.querySelectorAll('.payment-opt').forEach(o => o.classList.remove('selected'));
    document.getElementById('opt-' + method).classList.add('selected');
  }

  // ---------- LANJUT PEMBAYARAN ----------
  const DANA_NUMBER = '08987020983';
  const QRIS_DATA_STRING = 'AURORA HIJAB | Pembayaran QRIS via DANA ' + DANA_NUMBER;
  const DANA_QR_IMG = 'data:image/jpeg;base64,';
  const QRIS_REAL_IMG = 'data:image/jpeg;base64,';
  let lastOrder = null;
  let orderSeq = 1;

  function lanjutPembayaran(){
    const nama = document.getElementById('ordNama').value.trim();
    const hp = document.getElementById('ordHp').value.trim();
    const ig = document.getElementById('ordIg').value.trim();
    const alamat = document.getElementById('ordAlamat').value.trim();

    if(cart.length === 0){ alert('Keranjang masih kosong. Silakan pilih produk terlebih dahulu ya ✨'); return; }
    if(!nama || !hp || !ig || !alamat){ alert('Mohon lengkapi Nama, Alamat, Username Instagram, dan No. Handphone terlebih dahulu.'); return; }
    const checkedKeys = Array.from(document.querySelectorAll('.ord-check:checked')).map(c => c.dataset.key);
    if(checkedKeys.length === 0){ alert('Pilih minimal satu produk yang ingin dipesan.'); return; }
    if(!selectedPayment){ alert('Silakan pilih metode pembayaran terlebih dahulu.'); return; }

    const total = updateOrderTotal();
    const items = cart.filter(it => checkedKeys.includes(it.key));

    lastOrder = { nama, hp, ig, alamat, items, total, method: selectedPayment,
      invoiceNo: 'AH-' + Date.now().toString().slice(-8) + '-' + orderSeq,
      tanggal: new Date().toLocaleString('id-ID', { dateStyle:'long', timeStyle:'short' }) };

    showPaymentModal(selectedPayment, total);
  }

  function showPaymentModal(method, total){
    const modalContent = document.getElementById('modalContent');
    let html = '';
    if(method === 'cash'){
      html = `
        <div style="margin-bottom:10px;"><span class="cash-badge" style="font-size:.9rem;padding:8px 18px;"><i class="fa-solid fa-money-bill-wave"></i> Cash</span></div>
        <h3>Pembayaran Cash</h3>
        <div class="modal-sub">Silakan siapkan pembayaran tunai saat produk diambil di toko atau COD sesuai kesepakatan.</div>
        <div class="modal-rek">
          <div class="lbl">Alamat Pengambilan / COD</div>
          <div class="num" style="font-size:1rem;">Rancaekek Kencana</div>
        </div>
        <div class="modal-total">Total Bayar: <span class="amt">${formatRp(total)}</span></div>
        <button class="btn btn-block" onclick="showReceipt()"><i class="fa-solid fa-receipt"></i> Konfirmasi &amp; Lihat Nota</button>
      `;
    } else if(method === 'qris'){
      html = `
        <div class="qris-mark" style="justify-content:center;margin-bottom:8px;">
          <span class="qm-dot" style="background:#ED1C24"></span><span class="qm-dot" style="background:#8DC63F"></span>
          <span class="qm-dot" style="background:#F7941E"></span><span class="qm-dot" style="background:#2E3192"></span>
          <span class="qm-text">QRIS</span>
        </div>
        <h3>Scan QRIS</h3>
        <div class="modal-sub">Scan kode QR berikut menggunakan aplikasi e-wallet atau m-banking apapun yang mendukung QRIS.</div>
        <img class="modal-qr" src="${QRIS_REAL_IMG}" alt="QRIS Aurora Hijab">
        <div class="modal-total">Total Bayar: <span class="amt">${formatRp(total)}</span></div>
        <button class="btn btn-block" onclick="showReceipt()"><i class="fa-solid fa-receipt"></i> Konfirmasi &amp; Lihat Nota</button>
      `;
    } else if(method === 'dana'){
      html = `
        <div class="dana-logo" style="margin:0 auto 12px;"><i class="fa-solid fa-wallet"></i> DANA</div>
        <h3>Transfer ke DANA</h3>
        <div class="modal-sub">Transfer ke nomor e-wallet DANA berikut, atau scan QR profil di bawah ini.</div>
        <div class="modal-rek">
          <div class="lbl">Nomor DANA</div>
          <div class="num">0898-7020-983</div>
        </div>
        <img class="modal-qr" src="${DANA_QR_IMG}" alt="QR Profil DANA Aurora Hijab" style="width:170px;">
        <div class="modal-total">Total Bayar: <span class="amt">${formatRp(total)}</span></div>
        <button class="btn btn-block" onclick="showReceipt()"><i class="fa-solid fa-receipt"></i> Konfirmasi &amp; Lihat Nota</button>
      `;
    }
    modalContent.innerHTML = html;
    document.getElementById('paymentModal').classList.add('open');
  }

  const METHOD_LABEL = { cash:'Cash / COD', qris:'QRIS', dana:'DANA (0898-7020-983)' };

  function showReceipt(){
    if(!lastOrder) return;
    const o = lastOrder;
    const itemsHtml = o.items.map(it => `
      <div class="receipt-item">
        <div class="ri-left">
          <div class="ri-name">${it.name}</div>
          <div class="ri-meta">${it.color} &times; ${it.qty}</div>
        </div>
        <div class="ri-price">${formatRp(it.price * it.qty)}</div>
      </div>
    `).join('');

    const html = `
      <div class="receipt-brand"><i class="fa-solid fa-circle-check" style="color:#4CAF50;"></i></div>
      <h3>Nota Pembayaran</h3>
      <div class="modal-sub">Pesanan kamu sudah kami terima. Terima kasih sudah berbelanja di Aurora Hijab 🩷</div>
      <div class="receipt-box">
        <div class="receipt-row"><span>No. Invoice</span><span>${o.invoiceNo}</span></div>
        <div class="receipt-row"><span>Tanggal</span><span>${o.tanggal}</span></div>
        <div class="receipt-row"><span>Nama</span><span>${o.nama}</span></div>
        <div class="receipt-row"><span>No. HP</span><span>${o.hp}</span></div>
        <div class="receipt-row"><span>Instagram</span><span>${o.ig}</span></div>
        <div class="receipt-row"><span>Alamat</span><span>${o.alamat}</span></div>
        <div class="receipt-divider"></div>
        <div class="receipt-items">${itemsHtml}</div>
        <div class="receipt-divider"></div>
        <div class="receipt-row"><span>Metode Bayar</span><span>${METHOD_LABEL[o.method]}</span></div>
        <div class="receipt-row total"><span>Total Bayar</span><span>${formatRp(o.total)}</span></div>
      </div>
      <button class="btn btn-block" onclick="finishOrder()"><i class="fa-solid fa-check"></i> Tutup &amp; Selesai</button>
    `;
    document.getElementById('modalContent').innerHTML = html;
  }

  function finishOrder(){
    orderSeq += 1;
    cart = [];
    renderCart();
    document.getElementById('ordNama').value = '';
    document.getElementById('ordHp').value = '';
    document.getElementById('ordIg').value = '';
    document.getElementById('ordAlamat').value = '';
    selectedPayment = null;
    document.querySelectorAll('.payment-opt').forEach(o => o.classList.remove('selected'));
    document.querySelectorAll('input[name="payment"]').forEach(r => r.checked = false);
    lastOrder = null;
    closeModal();
  }

  function closeModal(){ document.getElementById('paymentModal').classList.remove('open'); }
  document.getElementById('paymentModal').addEventListener('click', (e) => {
    if(e.target.id === 'paymentModal') closeModal();
  });

  // init
  renderCart();
